index 76234ccfdcff..eeb6dc186c11 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2029,6 +2029,32 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(C2-X) --> X+(C-C2)
     if (match(Op1, m_Sub(m_ImmConstant(C2), m_Value(X))))
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
+
+    // C - ((C1 - X) & sign_mask) --> X & result_mask
+    // where sign_mask = ~((1<<k)-1), C1 & sign_mask == C, k >= 1
+    // and result_mask = C | ((C1 - C) << k)
+    // Example: 64 - ((71 - X) & -8) --> X & 120
+    {
+      Value *X;
+      const APInt *C1, *SignMask;
+      if (match(Op1, m_And(m_Sub(m_APInt(C1), m_Value(X)), m_APInt(SignMask)))) {
+        // sign_mask should be of the form ~((1<<k)-1)
+        // i.e., all bits set except for a contiguous run of low bits
+        APInt LowBits = ~(*SignMask);
+        if (LowBits.isMask() && !LowBits.isZero()) {
+          unsigned K = LowBits.getActiveBits();  // number of low bits
+          // Check C1 & sign_mask == C
+          const APInt &CApi = cast<ConstantInt>(C)->getValue();
+          if ((*C1 & *SignMask) == CApi) {
+            // Compute result_mask = C | ((C1 - C) << K)
+            APInt Diff = *C1 - CApi;
+            APInt ResultMask = CApi | (Diff << K);
+            return BinaryOperator::CreateAnd(X, ConstantInt::get(I.getType(), ResultMask));
+          }
+        }
+      }
+    }
+
   }

   const APInt *Op0C;

